#include <iostream>
#include <algorithm>
using namespace std;
bool func(string x,string y)
{
    return x+y>y+x;
}
int main()
{
    int n;
    cin>>n;
    string s[25];
    for(int i=0;i<=n-1;i++)
    {
        cin>>s[i];
    }
    sort(s,s+n,func);
    for(int i=0;i<=n-1;i++)
    {
        cout<<s[i];
    }
}
